/view>\n        <view\n          :class=\"[operationBtnClass('confirm', isPickerScrolling)]\"\n          :style=\"operationBtnStyle('confirm')\"\n          @tap.stop=\"confirmEvent\"\n        >\n          <slot name=\"confirm\">\n            {{ props.confirmText }}\n          </slot>\n        </view>\n      </view>\n\n      <!-- 内容区域 -->\n      <view :class=\"[ns.e('content')]\">\n        <picker-view\n          v-if=\"showPicker\"\n          :class=\"[ns.e('picker-view')]\"\n          :value=\"currentPickerIndex\"\n          :indicator-style=\"`height: ${props.indicatorHeight || 44}px;`\"\n          indicator-class=\"tn-picker-indicator\"\n          :immediate-change=\"immediateChange\"\n          @change=\"pickerViewChangeEvent\"\n          @pickstart=\"pickerViewPickStartEvent\"\n          @pickend=\"pickerViewPickerEndEvent\"\n        >\n          <picker-view-column\n            v-for=\"(item, index) in pickerData\"\n            :key=\"index\"\n            :class=\"[ns.e('picker-view-column')]\"\n          >\n            <view\n              v-for=\"(dItem, dIndex) in item\"\n              :key=\"dIndex\"\n              :class=\"ns.e('content-item')\"\n            >\n              <view\n                class=\"tn-text-ellipsis-1\"\n                :class=\"ns.em('content-item', 'data')\"\n              >\n                {{ dItem['label'] }}\n              </view>\n            </view>\n          </picker-view-column>\n        </picker-view>\n      </view>\n    </view>\n  </TnPopup>\n</template>\n\n<style lang=\"scss\" scoped>\n@import '../../../theme-chalk/src/picker.scss';\n</style>\n","import Component from 'C:/Users/35577/Downloads/easyai-uniapp-aigc/src/components/node_modules/@tuniao/tnui-vue3-uniapp/components/picker/src/picker.vue'\nwx.createComponent(Component)"],"names":["usePicker","usePickerCustomStyle"],"mappings":";;;;;AACA,MAAA,UAAoB,MAAA;;;;;;AAIpB,UAAM,QAAQ;AAGR,UAAA;AAAA,MACJ;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MAC